export const CALD_100 = [
  // ==================== EASY (30) ====================
  {id:"cald-201",d:"easy",t:"Growth and Development",q:"Which of the following is an example of DEVELOPMENT rather than growth?",c:["A. A child gaining 3 kilograms in one month","B. A child growing 2 inches taller over the summer","C. A child becoming more empathetic and learning to share","D. A child's head circumference increasing"],a:"C",e:"Development is a qualitative change in the organism as a whole — becoming more empathetic and learning to share are qualitative changes in social-emotional capacity, not measurable physical quantities."},
  {id:"cald-202",d:"easy",t:"Principles of Development",q:"Which principle states that 'there are social expectations for every developmental period'?",c:["A. Principle #3 — Development involves change","B. Principle #5 — Product of maturation and learning","C. Principle #7 — Developmental Tasks exist for every period","D. Principle #2 — Rate of development is unique"],a:"C",e:"Principle #7 states that there are social expectations for every developmental period which are often referred to as Developmental Tasks."},
  {id:"cald-203",d:"easy",t:"Stages of Human Development",q:"The AMNION is best described as:",c:["A. A disk-shaped group of tissues where small blood vessels intertwine","B. A cord with two arteries and one vein connecting baby to placenta","C. A bag or envelope that contains a clear fluid in which the developing embryo floats","D. The inner layer of cells that develops into the embryo"],a:"C",e:"The Amnion is a bag or envelope that contains a clear fluid in which the developing embryo floats — it is one of the three life-support systems for the embryo."},
  {id:"cald-204",d:"easy",t:"Domains of Development",q:"Fine motor development involves:",c:["A. Large muscles such as legs and arms","B. Small muscles such as those in the hand, fingers, lips, and tongue","C. The development of logical thinking and problem-solving","D. The development of language comprehension"],a:"B",e:"Fine motor development involves the SMALL muscles such as those in the hand, fingers, lips, and tongue — contrasted with gross motor (large muscles)."},
  {id:"cald-205",d:"easy",t:"Erikson's Psychosocial Theory",q:"The psychosocial crisis of the PRE-SCHOOL YEARS is:",c:["A. Trust vs. Mistrust","B. Autonomy vs. Shame and Doubt","C. Initiative vs. Guilt","D. Industry vs. Inferiority"],a:"C",e:"Initiative vs. Guilt is the crisis of the Pre-School Years (3-6 years). The virtue gained is Courage or the Ability to Take Risks."},
  {id:"cald-206",d:"easy",t:"Freud's Psychoanalytic Theory",q:"According to Freud, the LATENCY STAGE is characterized by:",c:["A. Sexual urges being awakened for the first time","B. An unconscious attraction to the opposite-sex parent","C. Sexual urges remaining repressed; focus on physical and academic skills","D. The pleasure zone being the mouth"],a:"C",e:"During the Latency Stage (age 6 to puberty), sexual urges remain repressed and the children's focus is the acquisition of physical and academic skills."},
  {id:"cald-207",d:"easy",t:"Piaget's Cognitive Development",q:"Which of the following is a characteristic of the PREOPERATIONAL STAGE?",c:["A. Conservation of number and volume","B. Object Permanence","C. Hypothetical-Deductive Reasoning","D. Egocentrism"],a:"D",e:"Egocentrism — the tendency of a child to only see his/her point of view and assume everyone else sees the same — is a key characteristic of the Preoperational Stage (2-7 years)."},
  {id:"cald-208",d:"easy",t:"Vygotsky's Socio-Cultural Theory",q:"The More Knowledgeable Other (MKO) in Vygotsky's theory refers to:",c:["A. A student who works independently without help","B. A competent adult or a more advanced peer who can assist the child's development","C. The biological readiness required before learning can occur","D. The cultural tools and artifacts available to a child"],a:"B",e:"The MKO (More Knowledgeable Other) is a competent adult like a teacher or parent, or a more advanced peer who can assist the child's development within the ZPD."},
  {id:"cald-209",d:"easy",t:"Kohlberg's Moral Development",q:"Level II of Kohlberg's Moral Development is called:",c:["A. Pre-Conventional Morality","B. Conventional Morality","C. Post-Conventional Morality","D. Universal Ethical Morality"],a:"B",e:"Level II is Conventional Morality — people at this level conform to the conventions/rules of society (follow norms)."},
  {id:"cald-210",d:"easy",t:"Bronfenbrenner's Ecological Theory",q:"The EXOSYSTEM is best described as:",c:["A. The child's direct environment like family and school","B. The connection between structures in the microsystem","C. The larger social system one step removed from the child with indirect impact","D. The cultural values, customs, and laws of society"],a:"C",e:"The Exosystem defines the larger social system in which the child does not function directly — it is one step removed from the child but has an indirect impact through the family unit."},
  {id:"cald-211",d:"easy",t:"Behaviorism",q:"Classical conditioning is also known as:",c:["A. Operant conditioning","B. Respondent or Pavlovian conditioning","C. Social learning theory","D. Instrumental conditioning"],a:"B",e:"Classical conditioning is also known as Respondent Conditioning or Pavlovian Conditioning — it refers to learning that occurs through the repeated association of two or more stimuli."},
  {id:"cald-212",d:"easy",t:"Operant Conditioning",q:"POSITIVE PUNISHMENT involves:",c:["A. Removing something negative to increase behavior","B. Adding something negative after undesired behavior to decrease future responses","C. Taking away something positive to decrease behavior","D. Adding something positive to increase behavior"],a:"B",e:"Positive Punishment involves ADDING a negative consequence after an undesired behavior happens to decrease future responses. Example: A child is sent to time-out (negative stimulus added)."},
  {id:"cald-213",d:"easy",t:"Bandura's Social Cognitive Theory",q:"According to Bandura, VICARIOUS CONSEQUENCES refer to:",c:["A. Consequences experienced directly by the learner","B. Consequences observed happening to a model that influence the learner","C. Consequences that have no effect on the learner's behavior","D. Consequences that only apply to animal learning"],a:"B",e:"Vicarious Consequences — the learner observes and imitates others' behavior while also observing the consequences that happen to the model (vicarious experiences)."},
  {id:"cald-214",d:"easy",t:"Cognitivism",q:"The Cognitivist paradigm argues that the 'black box' of the mind should be:",c:["A. Left unexplored — only observable behavior matters","B. Controlled through reinforcement and punishment","C. Opened and understood — the learner is viewed as an information processor","D. Shaped entirely by environmental conditioning"],a:"C",e:"The Cognitivist paradigm argues that the 'black box' of the mind should be opened and understood — the learner is viewed as an information processor (like a computer)."},
  {id:"cald-215",d:"easy",t:"Maslow's Hierarchy of Needs",q:"Which of the following is a component of LOVE AND BELONGING NEEDS according to Maslow?",c:["A. Oxygen, food, and water","B. Safety from physical attack","C. Inclusion, Affection, and Control","D. Self-esteem and recognition"],a:"C",e:"Love and Belonging Needs include Inclusion (part of a group), Affection (love and be loved), and Control (influence over others and self)."},
  {id:"cald-216",d:"easy",t:"Information Processing Theory",q:"SHORT-TERM MEMORY (STM) is best described as:",c:["A. An exact copy of stimuli held for fractions of a second","B. The information store that retains information as we consciously work on it","C. A permanent information story that lasts a lifetime","D. Memory that can only be accessed when prompted"],a:"B",e:"Short-Term Memory (STM) is the information store that retains information as we consciously work on it — it is temporary and limited in capacity."},
  {id:"cald-217",d:"easy",t:"Freud's Psychoanalytic Theory",q:"Which of the following is TRUE about the GENITAL STAGE?",c:["A. It spans from birth to 18 months","B. The pleasure zone is the anus","C. Sexual urges are fully repressed and academic focus dominates","D. It begins at the start of puberty when sexual urges are again awakened"],a:"D",e:"The Genital Stage begins at the start of puberty (puberty onwards) when sexual urges are again awakened, and adolescents focus their sexual urges toward the opposite sex."},
  {id:"cald-218",d:"easy",t:"Piaget's Cognitive Development",q:"DECENTERING in Piaget's Concrete Operational Stage means:",c:["A. The inability to focus on more than one aspect at a time","B. The ability to perceive different features of objects and situations","C. The ability to solve abstract problems without concrete objects","D. The process of achieving object permanence"],a:"B",e:"Decentering is the ability of the child to perceive the different features of objects and situations — the opposite of Centration (which only focuses on one aspect)."},
  {id:"cald-219",d:"easy",t:"Erikson's Psychosocial Theory",q:"The LOVE virtue in Erikson's Intimacy vs. Isolation stage:",c:["A. Refers only to romantic love between spouses","B. Includes love in a good marriage, love between friends, and love for neighbors and co-workers","C. Is the same as the Hope virtue from the first stage","D. Is only applicable to early adulthood females"],a:"B",e:"Love (the virtue of Intimacy vs. Isolation) includes not only the love in a good marriage but the love between friends, love for one's neighbor, co-worker, and compatriot as well."},
  {id:"cald-220",d:"easy",t:"Robert Gagne",q:"How many Events of Instruction did Robert Gagne propose?",c:["A. Five","B. Seven","C. Nine","D. Twelve"],a:"C",e:"Robert Gagne proposed NINE Events of Instruction, ranging from Gaining Attention (#1) to Enhancing Retention and Transfer (#9)."},
  {id:"cald-221",d:"easy",t:"Developmental Tasks",q:"'Learning to walk' and 'learning to talk' are developmental tasks associated with which stage?",c:["A. Middle Childhood","B. Infancy and Early Childhood","C. Adolescence","D. Early Adulthood"],a:"B",e:"Learning to walk, crawl, talk, and control body wastes are Developmental Tasks for Infancy and Early Childhood according to Havighurst."},
  {id:"cald-222",d:"easy",t:"Piaget's Cognitive Development",q:"CLASSIFICATION in Piaget's Concrete Operational Stage refers to:",c:["A. The ability to reverse mental operations","B. The ability to group or classify things according to one dimension or aspect","C. The ability to perceive multiple features simultaneously","D. The ability to arrange objects in order of magnitude"],a:"B",e:"Classification is the ability to group or classify things according to one dimension or aspect — a key achievement of the Concrete Operational Stage."},
  {id:"cald-223",d:"easy",t:"Maslow's Hierarchy of Needs",q:"Maslow is known for developing the concept of:",c:["A. Zone of Proximal Development","B. Hierarchy of Needs and Self-Actualization","C. Meaningful Learning Theory","D. Psychosocial Development Theory"],a:"B",e:"Abraham Maslow is most known for developing the Hierarchy of Needs and promoting the concept of Self-Actualization."},
  {id:"cald-224",d:"easy",t:"Kohlberg's Moral Development",q:"Level III of Kohlberg's stages is called:",c:["A. Pre-Conventional Morality","B. Conventional Morality","C. Post-Conventional Morality","D. Instrumental Morality"],a:"C",e:"Level III is Post-Conventional Morality — the moral principles that underlie the conventions of a society are understood, and one may follow or reject norms based on ethical principles."},
  {id:"cald-225",d:"easy",t:"Bronfenbrenner's Ecological Theory",q:"Bronfenbrenner emphasized that a child's own BIOLOGY is a primary environment fueling her development. This view reflects his renaming of the theory as:",c:["A. Sociocultural Theory","B. Ecological Developmental Theory","C. Bioecological Systems Theory","D. Environmental Psychology Theory"],a:"C",e:"Bronfenbrenner renamed his theory the Bioecological Systems Theory to emphasize that the child's own biology is a primary environment fueling her development."},
  {id:"cald-226",d:"easy",t:"Freud's Psychoanalytic Theory",q:"The ANAL STAGE in Freud's theory spans from:",c:["A. Birth to 18 months","B. 18 months to 3 years","C. Ages 3 to 6","D. Age 6 to puberty"],a:"B",e:"The Anal Stage spans from 18 months to 3 years. The child's focus of pleasure in this stage is the anus, and the child needs to work on toilet training."},
  {id:"cald-227",d:"easy",t:"Piaget's Cognitive Development",q:"REVERSIBILITY in Piaget's Concrete Operational Stage refers to:",c:["A. The ability to think in abstract and hypothetical terms","B. The ability to follow that certain operations can be done in reverse","C. The tendency to focus on only one aspect of a situation","D. The belief that psychological events like dreams are real"],a:"B",e:"Reversibility is the ability of the child to follow that certain operations or actions can be done in reverse — for example, understanding that subtraction reverses addition."},
  {id:"cald-228",d:"easy",t:"Classical Conditioning",q:"The UNCONDITIONED RESPONSE (UCR) is:",c:["A. A neutral stimulus that initially produces no response","B. A learned response that occurs after conditioning","C. A reflexive, involuntary response predictably caused by the UCS","D. The gradual disappearance of a conditioned response"],a:"C",e:"The Unconditioned Response (UCR) is a reflexive, involuntary response that is predictably caused by the UCS — it occurs automatically without learning."},
  {id:"cald-229",d:"easy",t:"Stages of Human Development",q:"The PLACENTA is a life-support system that:",c:["A. Contains clear fluid in which the embryo floats","B. Connects the baby to the mother through two arteries and one vein","C. Consists of disk-shaped tissues where small blood vessels from mother and offspring intertwine but do not join","D. Is the outer layer of cells that provides nutrition and support for the embryo"],a:"C",e:"The Placenta is a life-support system that consists of a disk-shaped group of tissues in which small blood vessels from the mother and the offspring intertwine but do not join."},
  {id:"cald-230",d:"easy",t:"Ausubel's Meaningful Learning",q:"Ausubel's theory is also called:",c:["A. Operant Conditioning Theory","B. Meaningful Learning or Subsumption Theory","C. Constructivist Theory","D. Social Learning Theory"],a:"B",e:"Ausubel's theory is called Meaningful Learning Theory or Subsumption Theory — he focused on the learning of school subjects and how meaningful learning occurs."},

  // ==================== MODERATE (50) ====================
  {id:"cald-231",d:"moderate",t:"Erikson's Psychosocial Theory",q:"A teacher in elementary school gives students a wide variety of tasks with clear achievable goals and recognizes their accomplishments. This is MOST likely to help students resolve which Eriksonian crisis positively?",c:["A. Trust vs. Mistrust","B. Initiative vs. Guilt","C. Industry vs. Inferiority","D. Identity vs. Role Confusion"],a:"C",e:"Industry vs. Inferiority (elementary school years) — providing achievable tasks and recognition of accomplishments helps students develop a sense of competence (Industry) rather than inferiority."},
  {id:"cald-232",d:"moderate",t:"Kohlberg and Piaget",q:"Kohlberg's moral stages parallel Piaget's cognitive stages in that:",c:["A. Both require formal operational thinking at ALL levels","B. Pre-Conventional morality parallels preoperational thinking; Conventional morality parallels concrete operations; Post-Conventional requires formal operations","C. Both theorists believed moral development ends at adolescence","D. Post-Conventional morality is achievable in the Concrete Operational Stage"],a:"B",e:"Kohlberg's levels parallel Piaget's stages: Pre-Conventional (preoperational), Conventional (concrete operations), Post-Conventional (requires formal operational thinking — abstract reasoning about principles)."},
  {id:"cald-233",d:"moderate",t:"Bandura's Social Cognitive Theory",q:"A student who KNOWS how to swim but refuses to demonstrate in front of the class because of embarrassment is exhibiting a gap between:",c:["A. Attention and Retention phases","B. Learning (acquisition) and Performance — the Motivational Process is missing","C. Motor Reproduction and Attention phases","D. Classical conditioning and operant conditioning"],a:"B",e:"Bandura distinguished between learning (acquisition) and performance — the student has learned (Attention, Retention, Motor Reproduction) but won't perform due to unfavorable conditions (Motivational Process missing)."},
  {id:"cald-234",d:"moderate",t:"Piaget's Cognitive Development",q:"A child believes that a tall, thin glass of water has MORE water than a short, wide glass — even after watching the same water being poured. This child has NOT yet achieved:",c:["A. Object Permanence","B. Conservation and Decentering","C. Classification","D. Seriation"],a:"B",e:"Conservation — the ability to know that properties (like volume) don't change despite appearance changes — and Decentering (considering multiple aspects) are both absent here. This is typical of Preoperational Stage."},
  {id:"cald-235",d:"moderate",t:"Vygotsky's Socio-Cultural Theory",q:"Which of the following BEST describes why Vygotsky considered social interaction more important than Piaget did?",c:["A. Vygotsky believed children are passive learners who need direction from adults","B. Vygotsky saw social interaction as the PRIMARY MECHANISM through which culture transmits cognitive tools and language that drive development","C. Vygotsky believed biological maturation occurs through social contact","D. Vygotsky rejected the idea that children could ever learn independently"],a:"B",e:"For Vygotsky, social interaction transmits cultural cognitive tools (especially language) that ARE the mechanism of cognitive development — not just a supplement to it."},
  {id:"cald-236",d:"moderate",t:"Freud and Erikson",q:"Both Freud's Phallic Stage and Erikson's Initiative vs. Guilt crisis occur during the same age period (3-6 years). What is the key distinction in their views?",c:["A. Both focus on sexual development as the primary driver of personality","B. Freud focuses on unconscious sexual conflicts with parents; Erikson focuses on developing a sense of purpose and taking initiative in activities","C. Erikson focuses on sexual drives while Freud focuses on social relationships","D. Both theorists agreed that guilt is the primary emotion of this period"],a:"B",e:"Freud focuses on unconscious sexual conflicts (Oedipus/Electra Complex) during the Phallic Stage. Erikson focuses on developing purposeful initiative in activities — the virtue is Courage/Purpose."},
  {id:"cald-237",d:"moderate",t:"Bronfenbrenner's Ecological Theory",q:"A student performs well academically when her parents and teachers communicate regularly about her progress. This BEST illustrates the influence of the:",c:["A. Microsystem","B. Mesosystem","C. Exosystem","D. Macrosystem"],a:"B",e:"The Mesosystem provides the connection between structures in the Microsystem — regular parent-teacher communication is a classic example of a healthy Mesosystem supporting development."},
  {id:"cald-238",d:"moderate",t:"Information Processing Theory",q:"The INTERFERENCE THEORY of forgetting states that:",c:["A. Information fades gradually from LTM when not rehearsed","B. Information was never properly encoded into memory in the first place","C. Forgetting LTM is due to the influence of other learning blocking the original memory","D. Information was stored in Sensory Memory and never transferred to STM"],a:"C",e:"Interference Theory — forgetting LTM is due to the influence of other learning interfering with the retrieval of the original information."},
  {id:"cald-239",d:"moderate",t:"Maslow's Hierarchy of Needs",q:"A child who has been homeless and hungry for weeks suddenly finds stable housing and food. According to Maslow, which needs are NOW being met, and which needs will emerge NEXT?",c:["A. Physiological needs are met; Safety Needs will emerge next","B. Esteem Needs are met; Self-Actualization emerges next","C. Love and Belonging Needs are met; Esteem Needs emerge next","D. Safety Needs are met; Physiological Needs emerge next"],a:"A",e:"Physiological needs (food, shelter) are being met. According to Maslow's hierarchy, Safety Needs (safety from physical attack, emotional attack, disease) will emerge as the next level to address."},
  {id:"cald-240",d:"moderate",t:"Classical Conditioning",q:"A student who experienced a strict teacher in Grade 3 now feels anxious around ALL teachers, even kind ones. This is an example of:",c:["A. Stimulus Discrimination","B. Extinction","C. Stimulus Generalization","D. Spontaneous Recovery"],a:"C",e:"Stimulus Generalization — the tendency for stimuli SIMILAR to the original CS (the strict teacher) to produce the same CR (anxiety) — now ALL teachers (similar stimuli) produce anxiety."},
  {id:"cald-241",d:"moderate",t:"Piaget's Cognitive Development",q:"A child says 'The rain is crying because it's sad.' This is an example of which Preoperational characteristic?",c:["A. Centration","B. Artificialism","C. Animism","D. Irreversibility"],a:"C",e:"Animism — the tendency of the child to attribute human-like traits (emotions like sadness, expressed through crying) to inanimate objects (rain) is a hallmark of Preoperational thinking."},
  {id:"cald-242",d:"moderate",t:"Operant Conditioning",q:"A student who is always praised for good behavior suddenly stops receiving praise. If the good behavior decreases over time, this illustrates:",c:["A. Classical Conditioning Extinction","B. Spontaneous Recovery","C. Stimulus Discrimination","D. Operant Extinction — removal of reinforcement decreases a previously reinforced behavior"],a:"D",e:"Operant Extinction — when a previously reinforced behavior (good behavior + praise) no longer produces reinforcement, the behavior gradually decreases."},
  {id:"cald-243",d:"moderate",t:"Erikson's Psychosocial Theory",q:"An elderly person who looks back on life and says 'I made the most of what I had, and I'm at peace with my choices' is demonstrating successful resolution of:",c:["A. Generativity vs. Stagnation","B. Intimacy vs. Isolation","C. Integrity vs. Despair","D. Identity vs. Role Confusion"],a:"C",e:"Integrity vs. Despair is the final Eriksonian crisis. Successful resolution results in Wisdom — accepting one's life as meaningful and being at peace with one's choices."},
  {id:"cald-244",d:"moderate",t:"Piaget vs. Vygotsky",q:"A teacher waits for students to reach 'readiness' before introducing new concepts (Piaget), while another teacher introduces concepts slightly above current ability with support (Vygotsky). Which approach does RESEARCH generally support as more effective?",c:["A. The Piagetian approach — waiting for natural readiness prevents frustration","B. The Vygotskian approach — instruction within the ZPD with scaffolding actively drives development","C. Both approaches produce identical outcomes","D. Neither approach has research support"],a:"B",e:"Research generally supports the Vygotskian approach — instruction within the ZPD with scaffolding actively promotes development, rather than waiting for natural readiness as Piaget suggested."},
  {id:"cald-245",d:"moderate",t:"Freud's Psychoanalytic Theory",q:"A person who is extremely messy, disorganized, and impulsive may have developed an ANAL EXPULSIVE personality. This results from fixation in the Anal Stage caused by:",c:["A. Too strict toilet training leading to excessive control","B. Too permissive toilet training leading to lack of self-control","C. Unresolved Oedipus Complex during the Phallic Stage","D. Oral deprivation during the Oral Stage"],a:"B",e:"Anal Expulsive — too permissive toilet training → lack of self-control, messiness, disorganization. Anal Retentive — too strict training → obsession with control, perfectionism, cleanliness."},
  {id:"cald-246",d:"moderate",t:"Kohlberg's Moral Development",q:"A student helps classmates because she enjoys the feeling of being considered 'a good person.' According to Kohlberg, she is reasoning at:",c:["A. Stage 1 — Punishment-Obedience","B. Stage 2 — Personal Benefit","C. Stage 3 — Good Boy-Nice Girl (Social Approval)","D. Stage 4 — Law and Order"],a:"C",e:"Stage 3 (Good Boy-Nice Girl) — ethical decisions are based on concern for or the opinions of others — seeking to be perceived as a good person by the social group."},
  {id:"cald-247",d:"moderate",t:"Ausubel's Meaningful Learning",q:"A student learns about 'vertebrates' and later encounters whales — automatically fitting whales into the vertebrates category based on existing knowledge. This is:",c:["A. Correlative Subsumption","B. Superordinate Learning","C. Derivative Subsumption","D. Combinatorial Learning"],a:"C",e:"Derivative Subsumption — whales are an instance or example of the concept (vertebrates) that the student has already learned. The new information is derived from the existing framework."},
  {id:"cald-248",d:"moderate",t:"Information Processing Theory",q:"A student uses the acronym 'HOMES' to remember the Great Lakes. This memory strategy is stored in which type of memory?",c:["A. Sensory Memory","B. Short-Term Memory only","C. Long-Term Memory as a Procedural Memory strategy","D. Subconscious Memory"],a:"C",e:"The HOMES acronym is a memory strategy — once well-learned, it is stored in Long-Term Memory (LTM) as a semantic/procedural strategy that can be retrieved and applied."},
  {id:"cald-249",d:"moderate",t:"Developmental Tasks",q:"'Reaching and maintaining satisfactory performance in one's occupational career' is a developmental task of:",c:["A. Early Adulthood","B. Late Adulthood","C. Middle Adulthood (30-60 years)","D. Adolescence"],a:"C",e:"Reaching and maintaining satisfactory performance in one's occupational career is a Developmental Task of Middle Adulthood (30-60 years) according to Havighurst."},
  {id:"cald-250",d:"moderate",t:"Bandura's Social Cognitive Theory",q:"Which of the following BEST describes why Bandura's theory is called 'Social COGNITIVE' Theory rather than just 'Social Learning' Theory?",c:["A. It emphasizes that all learning occurs through direct social contact only","B. It recognizes that cognitive processes (attention, retention, motivation) mediate the relationship between observation and behavior","C. It rejects the role of reinforcement in learning entirely","D. It focuses only on unconscious cognitive processes, not observable behavior"],a:"B",e:"Bandura's theory is 'Social Cognitive' because it recognizes that cognitive processes (attention, retention, motivation) mediate between what is observed socially and what behavior is performed."},
  {id:"cald-251",d:"moderate",t:"Piaget's Cognitive Development",q:"A child understands that 8÷2=4 AND that 4×2=8. This understanding demonstrates which Concrete Operational skill?",c:["A. Object Permanence","B. Egocentrism","C. Reversibility","D. Animism"],a:"C",e:"Reversibility — the understanding that mathematical operations can be reversed (division is the reverse of multiplication) is a key achievement of the Concrete Operational Stage."},
  {id:"cald-252",d:"moderate",t:"Erikson's Psychosocial Theory",q:"The REPUDIATION maladaptation in Erikson's Identity stage involves:",c:["A. Being too committed to one identity with no flexibility","B. Rejecting their membership in the world of adults and their need for an identity","C. Being overly trusting and gullible","D. Imposing one's beliefs on others without regard for their rights"],a:"B",e:"Repudiation (maladaptation of Identity stage) — to reject their membership in the world of adults; they reject their identities and their need for an identity."},
  {id:"cald-253",d:"moderate",t:"Classical Conditioning",q:"A student is afraid of a math quiz (CS) because it was always paired with public shaming (UCS) by a former teacher. When the student moves to a new school with a supportive math teacher, the anxiety gradually disappears over time. This is:",c:["A. Stimulus Discrimination","B. Stimulus Generalization","C. Extinction","D. Spontaneous Recovery"],a:"C",e:"Extinction — when the CS (math quiz) is repeatedly presented WITHOUT the UCS (public shaming), the CR (anxiety) gradually diminishes through Extinction."},
  {id:"cald-254",d:"moderate",t:"Maslow and Teaching",q:"A teacher uses a trauma-informed approach by first ensuring students feel physically safe, then building a caring classroom community before focusing on academic achievement. This sequencing BEST reflects:",c:["A. Piaget's cognitive stages","B. Vygotsky's ZPD scaffolding","C. Maslow's Hierarchy of Needs — meeting lower-order needs before higher-order needs","D. Erikson's Industry vs. Inferiority stage"],a:"C",e:"Maslow's Hierarchy — Safety Needs (physical safety) must be met before Love and Belonging Needs (classroom community), which must be met before Esteem Needs (academic achievement/recognition)."},
  {id:"cald-255",d:"moderate",t:"Bronfenbrenner's Ecological Theory",q:"The interaction between a child's MATURING BIOLOGY, his IMMEDIATE FAMILY/COMMUNITY ENVIRONMENT, and the SOCIETAL LANDSCAPE fuels and steers development. This describes the core premise of:",c:["A. Piaget's Constructivism","B. Bronfenbrenner's Bioecological Systems Theory","C. Kohlberg's Moral Development","D. Erikson's Psychosocial Theory"],a:"B",e:"This is the core premise of Bronfenbrenner's Bioecological Systems Theory — the interaction between the child's own biology, immediate environment, and broader societal context drives development."},
  {id:"cald-256",d:"moderate",t:"Freud's Psychoanalytic Theory",q:"A child in the LATENCY STAGE (6 to puberty) primarily:",c:["A. Experiences intense sexual urges directed at the opposite-sex parent","B. Focuses on physical and academic skill acquisition while sexual urges are repressed","C. Develops the Superego for the first time","D. Learns to control bodily functions through toilet training"],a:"B",e:"In the Latency Stage, sexual urges remain repressed and children focus on acquiring physical and academic skills — boys relate more with boys, and girls with girls."},
  {id:"cald-257",d:"moderate",t:"Operant Conditioning",q:"A teacher reduces homework load when students consistently participate well in class discussions. The reduction in homework is a form of:",c:["A. Positive Punishment","B. Positive Reinforcement","C. Negative Punishment","D. Negative Reinforcement"],a:"D",e:"Negative Reinforcement — REMOVING something negative (homework) to INCREASE a desired behavior (class participation). The behavior increases because an aversive stimulus is removed."},
  {id:"cald-258",d:"moderate",t:"Piaget's Cognitive Development",q:"ARTIFICIAL ISM in the Preoperational Stage refers to:",c:["A. The tendency to attribute human characteristics to inanimate objects","B. The belief that natural events such as rain and thunder are man-made","C. The inability to understand that some things remain unchanged despite appearance changes","D. Assuming that everyone else sees the world the same way as the child"],a:"B",e:"Artificialism is the belief that natural events (rain, thunder, the sun) are man-made — the child believes that humans or divine powers created these natural phenomena."},
  {id:"cald-259",d:"moderate",t:"Information Processing Theory",q:"GENERAL TRANSFER of learning occurs when:",c:["A. A specific skill is applied in a similar situation","B. More complex skills are built on simpler prior skills","C. Previously learned principles are applied to dissimilar situations","D. Learning transfers to tasks at the same level of difficulty"],a:"C",e:"General Transfer — applying principles previously learned to dissimilar situations. Example: Applying general study habits (previously learned) to an entirely different subject."},
  {id:"cald-260",d:"moderate",t:"Developmental Tasks",q:"'Developing conscience, morality, and a scale of values' is a developmental task associated with:",c:["A. Infancy","B. Adolescence","C. Early Adulthood","D. Middle and Late Childhood (6-12 years)"],a:"D",e:"Developing conscience, morality, and a scale of values is a Developmental Task of Middle and Late Childhood (6-12 years) according to Havighurst."},
  {id:"cald-261",d:"moderate",t:"Vygotsky's Socio-Cultural Theory",q:"Which of the following activities MOST effectively targets a student's Zone of Proximal Development?",c:["A. Assigning tasks the student can already complete independently with no challenge","B. Assigning tasks far beyond current ability with no support","C. Assigning tasks slightly above current ability with teacher guidance and gradual removal of support","D. Avoiding challenging tasks to protect the student's self-esteem"],a:"C",e:"Tasks slightly above current ability WITH scaffolding (gradual removal of support) target the ZPD — the 'learning zone' between what the child can do alone and what they can do with guidance."},
  {id:"cald-262",d:"moderate",t:"Robert Gagne",q:"In Gagne's Nine Events of Instruction, 'Stimulating recall of prior learning' corresponds to which event?",c:["A. Event 1 — Gaining Attention","B. Event 2 — Informing learners of the objective","C. Event 3 — Stimulating recall of prior learning (Retrieval)","D. Event 5 — Providing learning guidance"],a:"C",e:"Event #3 in Gagne's Nine Events is Stimulating Recall of Prior Learning (Retrieval) — activating what students already know before presenting new content."},
  {id:"cald-263",d:"moderate",t:"Piaget and Classroom Application",q:"A teacher uses CONCRETE MANIPULATIVES (actual blocks, counters) while teaching place value to Grade 2 students. Which Piagetian principle BEST justifies this approach?",c:["A. Formal Operational Stage — students can handle abstract concepts","B. Sensorimotor Stage — students learn through muscle movement","C. Concrete Operational Stage — children think logically but only in terms of concrete objects","D. Preoperational Stage — children can use symbolic function"],a:"C",e:"The Concrete Operational Stage principle — children can think logically but only in terms of concrete objects. Manipulatives provide the concrete grounding needed for logical operations at this age."},
  {id:"cald-264",d:"moderate",t:"Erikson and Identity",q:"A high school student who copies the latest fashion, music tastes, and opinions of her peer group without forming her own identity may be experiencing which outcome of the Identity vs. Role Confusion stage?",c:["A. Fanaticism — imposing her identity on others","B. Repudiation — rejecting the adult world's identity norms","C. Role Confusion — not finding a stable, consistent sense of who she is","D. Withdrawal — depression and psychosis"],a:"C",e:"Role Confusion (the negative outcome of Identity vs. Role Confusion) — the student has not found her own stable identity and simply adopts whoever she is around, resulting in role confusion."},
  {id:"cald-265",d:"moderate",t:"Behaviorism Applied",q:"A dog is trained to salivate to a bell. Later, the dog also salivates to a similar-sounding doorbell but NOT to a clearly different foghorn. Which two classical conditioning processes are demonstrated?",c:["A. Acquisition and Extinction","B. Spontaneous Recovery and Stimulus Discrimination","C. Stimulus Generalization (doorbell) and Stimulus Discrimination (foghorn)","D. Extinction (doorbell) and Acquisition (foghorn)"],a:"C",e:"Stimulus Generalization (doorbell is similar to bell → salivates) AND Stimulus Discrimination (foghorn is distinctly different → no salivation) are both demonstrated simultaneously."},
  {id:"cald-266",d:"moderate",t:"Piaget's Cognitive Development",q:"The EQUILIBRATION process is triggered when:",c:["A. A child successfully assimilates all new experiences without conflict","B. A child experiences DISEQUILIBRIUM — when existing schemas fail to explain a new experience","C. A child enters a new Piagetian stage automatically through biological maturation","D. A child watches a model perform a new behavior successfully"],a:"B",e:"Equilibration is triggered by Disequilibrium — when existing schemas fail to explain a new experience. This motivates assimilation or accommodation to restore cognitive balance."},
  {id:"cald-267",d:"moderate",t:"Freud's Personality Components",q:"The ID, EGO, and SUPEREGO represent Freud's structural model of personality. Which statement CORRECTLY describes their relationship?",c:["A. The Id is the most rational; the Superego seeks pleasure; the Ego is the moral component","B. The Id seeks immediate pleasure; the Ego balances Id and reality; the Superego is the moral conscience","C. The Ego develops first; then the Id; then the Superego","D. All three components operate at the same level of consciousness"],a:"B",e:"Correct structural model: Id (pleasure principle, immediate gratification) → Ego (reality principle, balances Id and reality) → Superego (morality principle, conscience)."},
  {id:"cald-268",d:"moderate",t:"Kohlberg's Moral Development",q:"A driver stops at a red light even though it is 3 AM and no other cars are visible. He stops because 'Rules are rules, and maintaining social order matters.' This reflects:",c:["A. Stage 2 — Personal benefit","B. Stage 3 — Social approval","C. Stage 4 — Law and Order Orientation","D. Stage 5 — Social Contract"],a:"C",e:"Stage 4 (Law and Order Orientation) — right behavior consists in doing one's duty and maintaining the given social order for its own sake, regardless of personal benefit or social approval."},
  {id:"cald-269",d:"moderate",t:"Maslow and Deficiency vs. Growth Needs",q:"Which of the following pairs of needs are DEFICIENCY NEEDS (D-needs) according to Maslow?",c:["A. Self-Actualization and Esteem","B. Esteem and Love/Belonging","C. Physiological, Safety, Love/Belonging, and Esteem — all four lower-level needs","D. Self-Actualization alone"],a:"C",e:"All FOUR lower-level needs (Physiological, Safety, Love/Belonging, and Esteem) are Deficiency Needs (D-needs) — they motivate behavior when deficient and reduce motivation when satisfied."},
  {id:"cald-270",d:"moderate",t:"Ausubel's Meaningful Learning",q:"Which of the following BEST describes why Ausubel placed ADVANCE ORGANIZERS at the beginning of a lesson?",c:["A. To test what students don't know before instruction","B. To provide an entertaining introduction to reduce anxiety","C. To activate prior knowledge and provide an overview that bridges what is known with what is to be learned","D. To summarize the lesson after it has been delivered"],a:"C",e:"Advance Organizers activate prior knowledge and provide an overview of the information to be covered — they bridge existing knowledge with new content, preparing learners for meaningful learning."},
  {id:"cald-271",d:"moderate",t:"Piaget's Cognitive Development",q:"REALISM in Piaget's Preoperational Stage refers to:",c:["A. The ability to think logically using concrete objects","B. The belief that psychological events such as dreams are real","C. The ability to see the world from multiple perspectives","D. The tendency to attribute life to inanimate objects"],a:"B",e:"Realism is the belief that psychological events, such as dreams, are real — a preoperational child may genuinely believe their dreams actually happened."},
  {id:"cald-272",d:"moderate",t:"Bandura's Social Cognitive Theory",q:"A student watching a classmate get praised for answering correctly decides to also try answering questions in class. This is an example of:",c:["A. Classical Conditioning — being conditioned by the classroom bell","B. Vicarious Reinforcement — observing the model's positive consequences motivates similar behavior","C. Negative Reinforcement — removing something negative to increase behavior","D. Intrinsic Motivation only — no external influence involved"],a:"B",e:"Vicarious Reinforcement — observing the positive consequences (praise) that happened to the model (classmate) motivates the observer to perform the same behavior (answering questions)."},
  {id:"cald-273",d:"moderate",t:"Stages of Human Development",q:"The ECTODERM layer of the embryo develops into:",c:["A. Digestive and respiratory systems","B. Circulatory, skeletal, and muscular systems","C. Nervous system, sensory receptors, and skin parts","D. Excretory and reproductive systems"],a:"C",e:"The Ectoderm (outermost layer) becomes the nervous system, sensory receptors, and skin parts — the outermost layer of the body."},
  {id:"cald-274",d:"moderate",t:"Robert Gagne",q:"Gagne's Event #9 — 'Enhancing retention and transfer' — is MOST similar to which concept from another theory?",c:["A. Freud's concept of sublimation","B. Ausubel's concept of meaningful learning and advance organizers","C. Vygotsky's concept of the ZPD","D. Atkinson-Shiffrin's concept of long-term memory consolidation and General Transfer"],a:"D",e:"Enhancing retention and transfer (Gagne Event 9) is most similar to LTM consolidation and General Transfer (Atkinson-Shiffrin / Information Processing Theory) — ensuring learning is retained and applied to new situations."},
  {id:"cald-275",d:"moderate",t:"Piaget and Language",q:"Piaget believed that language is a PRODUCT of cognitive development. What does this imply about the relationship between language and thought?",c:["A. Language drives thought — children must develop language before they can think","B. Thought develops independently of language; language merely expresses what is already cognitively known","C. Language and thought are identical and develop at exactly the same rate","D. Language is irrelevant to cognitive development in Piaget's view"],a:"B",e:"For Piaget, thought develops first (through action on the environment) and language expresses what is already cognitively known — thought is primary, language is secondary."},
  {id:"cald-276",d:"moderate",t:"Erikson's Psychosocial Theory",q:"The CARING virtue in Erikson's Generativity vs. Stagnation stage manifests as:",c:["A. The ability to live by society's standards and find a place in the community","B. The desire to take care of other people and assist the next generation in becoming competent","C. Acceptance of one's life as meaningful and being at peace with mortality","D. The ability to form deep, intimate relationships with others"],a:"B",e:"Caring (the virtue of Generativity) manifests as the desire to take care of other people and to assist the next generation in becoming competent and mature individuals."},
  {id:"cald-277",d:"moderate",t:"Kohlberg's Moral Development",q:"Which of the following CORRECTLY matches Kohlberg's stage with its key characteristic?",c:["A. Stage 1 — Social Approval; Stage 3 — Consequences; Stage 5 — Personal Benefit","B. Stage 2 — Personal Benefit (IRO); Stage 4 — Law and Order; Stage 6 — Universal Ethical Principles","C. Stage 3 — Universal Principles; Stage 5 — Good Boy-Nice Girl; Stage 6 — Social Contract","D. Stage 1 — Social Contract; Stage 4 — Punishment-Obedience; Stage 6 — Personal Benefit"],a:"B",e:"Correct matching: Stage 2 (Instrumental Relativist — personal benefit), Stage 4 (Law and Order — duty and social order), Stage 6 (Universal Ethical Principles — self-chosen principles of conscience)."},
  {id:"cald-278",d:"moderate",t:"Metacognition",q:"PERSON VARIABLES in metacognition refers to:",c:["A. Knowledge about the nature of the task and its demands","B. Knowledge about the strategies you use to learn","C. Knowledge about how human beings learn and process information, including knowledge of one's own learning processes","D. Awareness of specific strategies to maintain attention"],a:"C",e:"Person Variables refer to knowledge about how human beings learn and process information, as well as individual knowledge of one's own learning processes and preferences."},
  {id:"cald-279",d:"moderate",t:"Freud's Topographical Model",q:"The PRECONSCIOUS/SUBCONSCIOUS in Freud's topographical model is best described as:",c:["A. Everything that is in our active, aware consciousness","B. All the things we don't know that affect our behavior — buried to avoid extreme anxiety","C. The part that is right below the surface, accessible when prompted but not in active consciousness","D. The moral and ethical component of personality"],a:"C",e:"The Preconscious/Subconscious is right below the surface — it is still 'hidden' somewhat unless we search for it but CAN be accessed when prompted. Examples: phone numbers, childhood memories."},
  {id:"cald-280",d:"moderate",t:"Piaget's Cognitive Development",q:"A child who has achieved CONSERVATION OF NUMBER can understand that:",c:["A. The moon doesn't really follow her as she walks","B. A rolling ball continues to exist even when out of sight","C. 7 objects arranged in a spread-out line are the same number as 7 objects closely clustered","D. A ball of clay and a flat pancake of the same clay have the same mass"],a:"C",e:"Conservation of Number — the ability to know that the NUMBER of objects doesn't change despite a change in their spatial arrangement. Both line and cluster have 7 objects."},

  // ==================== DIFFICULT (20) ====================
  {id:"cald-281",d:"difficult",t:"Integrated Theories",q:"A teacher argues that 'good teaching means meeting students where they are.' From Piaget's perspective, 'where they are' refers to their current SCHEMA and STAGE. From Vygotsky's perspective, 'where they are' refers to their ZPD. What is the KEY PRACTICAL DIFFERENCE between these two starting points?",c:["A. Piaget focuses on readiness and waits for stage emergence; Vygotsky focuses on the upper edge of the ZPD and uses instruction to push development forward","B. Piaget focuses on social context; Vygotsky focuses on individual biological maturation","C. Both theorists define 'where students are' identically — in terms of observable behavior","D. Piaget advocates for instructional challenge; Vygotsky advocates for waiting for natural readiness"],a:"A",e:"Key difference: Piaget says teach AT the student's current stage (readiness-based). Vygotsky says teach WITHIN the ZPD — slightly above current ability — to actively drive development forward."},
  {id:"cald-282",d:"difficult",t:"Bronfenbrenner and Kohlberg",q:"A child grows up in a country where corruption is normalized at the Macrosystem level. Despite this, the child's parents model ethical behavior at the Microsystem level. According to BOTH Bronfenbrenner AND Kohlberg, what is the MOST LIKELY developmental outcome?",c:["A. The Macrosystem inevitably determines moral reasoning — the child will adopt Post-Conventional morality to resist corruption","B. The Microsystem (parental modeling) provides a strong counter-influence that can support higher moral development even within a corrupt Macrosystem, but internal moral reasoning (Kohlberg) also plays a role","C. The child will automatically develop Stage 1 morality due to the punitive corrupt system","D. Bronfenbrenner and Kohlberg's theories cannot be integrated because they address different domains"],a:"B",e:"Microsystem influences (parental ethical modeling) can provide powerful counter-influences to Macrosystem norms. Kohlberg's stages of moral reasoning are also internally driven — higher moral development is still possible."},
  {id:"cald-283",d:"difficult",t:"Piaget's Cognitive Development",q:"A researcher uses a simplified version of Piaget's conservation task (with familiar, culturally relevant objects) and finds that children demonstrate conservation 2-3 years EARLIER than Piaget predicted. This finding MOST DIRECTLY challenges which aspect of Piaget's theory?",c:["A. The existence of Object Permanence in the Sensorimotor Stage","B. The universality and fixed timing of Piaget's stages — cultural familiarity and task design affect when abilities emerge","C. The sequence of stages — conservation precedes egocentrism in simplified tasks","D. The Formal Operational Stage's dependence on biological maturation"],a:"B",e:"This challenges the universality and fixed timing (age norms) of Piaget's stages — the stages may be correct in sequence but the ages may be underestimates when tasks use familiar, simplified materials."},
  {id:"cald-284",d:"difficult",t:"Integrated Theories",q:"Which of the following BEST illustrates the integration of Bandura's Motivational Process phase with Maslow's Hierarchy of Needs?",c:["A. A student assimilates (Piaget) a new math schema after watching a teacher model (Bandura) it — motivated by homework avoidance (negative reinforcement)","B. A student who has watched peers perform well observes BUT does NOT perform because her self-esteem is so low she doesn't believe she can succeed (unmet Esteem Need blocks Motivational Process)","C. A student is classically conditioned to fear performance (Pavlov) despite having watched peers succeed (Bandura) because of a strict teacher","D. A student at the Concrete Operational Stage (Piaget) cannot perform Formal Operational tasks regardless of motivational factors (Maslow)"],a:"B",e:"Unmet Esteem Needs (Maslow) can block the Motivational Process (Bandura) — even when the student has attended, retained, and has the motor ability, low self-esteem prevents performance."},
  {id:"cald-285",d:"difficult",t:"Erikson and Freud Integration",q:"Freud's theory ends at the GENITAL STAGE (puberty onwards) while Erikson's theory continues through EIGHT stages across the full lifespan. What does Erikson's extension REVEAL about a limitation in Freud's theory?",c:["A. Freud's theory is more comprehensive because it covers childhood in greater detail","B. Freud overemphasized the role of social relationships in adult development","C. Freud's theory underestimates adult development — personality and psychosocial challenges continue to evolve throughout adulthood, not just in childhood","D. Erikson rejected all of Freud's core concepts including the unconscious"],a:"C",e:"Erikson's extension reveals that Freud's focus on early childhood (ending at puberty) underestimates adult development — significant psychosocial challenges (Intimacy, Generativity, Integrity) occur throughout adulthood."},
  {id:"cald-286",d:"difficult",t:"Vygotsky Applied",q:"A critical thinker argues that Vygotsky's ZPD concept is CIRCULAR: we define the ZPD as what a child can do WITH help, but we only know their ZPD BY providing help. How would a Vygotskian educator BEST respond to this criticism?",c:["A. Agree — the ZPD is a theoretical construct that cannot guide practical instruction","B. The ZPD's circularity is actually a STRENGTH — dynamic assessment (testing through scaffolded interaction) is more informative than static testing, revealing not just current ability but learning potential","C. The ZPD can be measured through standardized tests that are equally accurate","D. The criticism is valid — Vygotsky's theory is not applicable to real classroom practice"],a:"B",e:"The ZPD's 'circularity' is actually its pedagogical strength — dynamic assessment (measuring through scaffolded interaction) reveals LEARNING POTENTIAL (ZPD) rather than just current static ability, making it more instructionally useful."},
  {id:"cald-287",d:"difficult",t:"Piaget and Constructivism Applied",q:"A school eliminates direct instruction entirely, arguing that 'children construct their own knowledge' (Piaget). A critic argues this misapplies Piaget. What is the VALID critique?",c:["A. Piaget believed teachers should never interact with students during learning","B. Piaget's Constructivism does NOT mean eliminating all instruction — it means creating environments where students can ACT on materials and experience, with teacher facilitation of schema-challenging experiences","C. Piaget believed direct instruction is always superior to discovery learning","D. Piaget's theory only applies to children below age 7 — older students need direct instruction always"],a:"B",e:"Piaget's Constructivism does not mean no instruction — it means creating rich environments with materials and experiences that challenge schemas, with teacher facilitation. Complete elimination of instruction misapplies Piaget."},
  {id:"cald-288",d:"difficult",t:"Kohlberg's Moral Development",q:"A person at Stage 6 (Universal Ethical Principles) may DISOBEY a democratically passed law. A person at Stage 5 (Social Contract) upholds democratic processes even if they disagree with the outcome. What does this distinction reveal about Stage 6?",c:["A. Stage 6 is morally inferior to Stage 5 because it ignores democratic consensus","B. Stage 6 places self-chosen universal principles of conscience ABOVE democratic consensus — it is a more autonomous and principled form of moral reasoning that most adults never reach","C. Stages 5 and 6 are essentially identical — both prioritize society's well-being","D. Stage 5 is always more justifiable than Stage 6 because democracy reflects collective wisdom"],a:"B",e:"Stage 6 places universal self-chosen ethical principles (conscience) above democratic consensus — it represents the most autonomous, principled moral reasoning. Kohlberg considered it the highest but rarest stage."},
  {id:"cald-289",d:"difficult",t:"Integrated Theories",q:"A student has met all lower-level needs, is in the Formal Operational Stage, has strong scaffolding from an MKO, and has appropriate advance organizers — yet still fails to learn effectively. Based on ALL theories discussed, what is the MOST LIKELY remaining barrier?",c:["A. Their Superego is blocking learning through excessive guilt","B. They have not yet resolved the Trust vs. Mistrust crisis","C. Metacognitive deficits — they lack awareness of their own learning strategies, cannot evaluate strategy effectiveness, and do not self-regulate learning","D. They are still in the Concrete Operational Stage despite appearing to be at Formal Operational"],a:"C",e:"When all other factors are addressed (needs, cognitive stage, scaffolding, prior knowledge activation), metacognitive deficits — inability to self-regulate, monitor, and evaluate learning strategies — become the key remaining barrier."},
  {id:"cald-290",d:"difficult",t:"Developmental Psychology",q:"A researcher proposes that the sequence of developmental stages is UNIVERSAL, but the AGE at which each stage is reached varies by cultural context. Which theoretical position does this MOST closely represent?",c:["A. Pure Nativism — all development is biologically predetermined","B. Pure Environmentalism — all development is shaped by the environment","C. A modified Piagetian position consistent with cross-cultural research — sequence is biologically determined, timing is culturally influenced","D. A strict Vygotskian position that rejects all universal developmental stages"],a:"C",e:"Cross-cultural research supports the SEQUENCE being universal (consistent with Piaget's biological basis) while the TIMING varies by cultural context (consistent with Vygotsky's cultural influence) — a modified interactionist position."},
  {id:"cald-291",d:"difficult",t:"Maslow and Erikson Integration",q:"At which point do Maslow's Hierarchy and Erikson's psychosocial stages MOST STRONGLY converge, and what is the implication for educators?",c:["A. They never converge — they address entirely different domains of development","B. Esteem Needs (Maslow) and Industry vs. Inferiority (Erikson) both address the elementary school child's need for competence, mastery, and recognition — educators must SIMULTANEOUSLY address need satisfaction AND psychosocial task resolution","C. Self-Actualization (Maslow) and Trust vs. Mistrust (Erikson) converge — both address the foundation of healthy development","D. Love and Belonging (Maslow) and Integrity vs. Despair (Erikson) converge — both address the need for meaningful relationships in old age"],a:"B",e:"Esteem Needs (Maslow) and Industry vs. Inferiority (Erikson) both address competence and mastery during elementary school years — educators must address both need satisfaction AND psychosocial task resolution simultaneously for optimal development."},
  {id:"cald-292",d:"difficult",t:"Piaget and Information Processing",q:"How do Piaget's SCHEMA and Ausubel-Atkinson's LONG-TERM MEMORY STRUCTURES relate to each other conceptually?",c:["A. They are identical concepts — Piaget and Ausubel used different terms for the same process","B. Both describe organized cognitive structures for storing and processing knowledge, but Piaget emphasizes active construction through action, while Atkinson-Shiffrin emphasizes encoding, storage, and retrieval processes","C. Schema (Piaget) is purely biological; LTM structures (Atkinson-Shiffrin) are purely environmental","D. They are completely unrelated — schemas apply only to children; LTM structures apply only to adults"],a:"B",e:"Both describe organized knowledge structures, but differ in emphasis: Piaget stresses ACTIVE CONSTRUCTION through environmental interaction; Atkinson-Shiffrin stresses ENCODING, STORAGE, and RETRIEVAL processes in an information-processing framework."},
  {id:"cald-293",d:"difficult",t:"Vygotsky and Bandura",q:"Both Vygotsky and Bandura emphasize the importance of SOCIAL CONTEXT in learning. What is the KEY DISTINCTION between their views on HOW social context drives learning?",c:["A. Vygotsky focuses on internal cognitive processes; Bandura focuses on external social influences only","B. Vygotsky sees social interaction as the mechanism through which cultural cognitive tools and language are internalized to drive cognitive development; Bandura sees social observation as a model for behavior acquisition through attention, retention, reproduction, and motivation","C. Vygotsky and Bandura have identical mechanisms for social learning","D. Bandura focuses on unconscious modeling; Vygotsky focuses on conscious imitation"],a:"B",e:"Vygotsky: social interaction internalizes cultural cognitive TOOLS (language, thought) → drives cognitive development. Bandura: social OBSERVATION of models → behavior acquisition through cognitive mediating processes (ARMM)."},
  {id:"cald-294",d:"difficult",t:"Freud and Defense Mechanisms Advanced",q:"A student who consistently fails in mathematics develops an intense passion for art and consistently wins school art competitions. Freud would MOST accurately explain this as:",c:["A. Repression — pushing math anxiety into the unconscious","B. Projection — attributing math failure to the teacher","C. Sublimation — channeling math-related frustration and energy into a socially valued activity (art)","D. Reaction Formation — converting math anxiety into the opposite: math enthusiasm"],a:"C",e:"Sublimation — channeling the energy, frustration, and anxiety from math failure into a socially productive and valued activity (art). The ID's energy is redirected constructively."},
  {id:"cald-295",d:"difficult",t:"Erikson and Identity Formation",q:"Research on IDENTITY FORMATION in multicultural societies suggests that adolescents in immigrant families often experience 'bicultural identity' — integrating two cultural identities. From Erikson's perspective, this represents:",c:["A. Failure to resolve the Identity vs. Role Confusion crisis — confusion about which culture to belong to","B. A more complex but potentially richer form of Identity resolution — achieving Fidelity that integrates multiple cultural standards rather than choosing one","C. Fanaticism — imposing one culture's identity standards on others","D. Repudiation — rejecting both cultures' identity frameworks"],a:"B",e:"Bicultural identity represents a more complex but potentially richer resolution of the Identity crisis — achieving Fidelity (ability to live by and integrate multiple standards from multiple communities)."},
  {id:"cald-296",d:"difficult",t:"Piaget and Assessment",q:"A teacher uses DYNAMIC ASSESSMENT — testing students by providing graduated hints during the test to see how much support they need. This approach is MOST theoretically grounded in:",c:["A. Piaget's concept of Stage-appropriate readiness testing","B. Vygotsky's ZPD — testing reveals the range of learning potential with support, not just current independent ability","C. Maslow's concept of meeting needs before assessing","D. Gagne's Nine Events of Instruction — assessing after all events are completed"],a:"B",e:"Dynamic Assessment is directly grounded in Vygotsky's ZPD — it measures not just current independent ability but the RANGE of what a student can do WITH various levels of support (their learning potential)."},
  {id:"cald-297",d:"difficult",t:"Integrated Theories",q:"A school implements THREE reforms: (1) ensures breakfast programs for hungry students (Maslow), (2) uses peer tutoring with advanced students guiding struggling ones (Vygotsky), and (3) provides skill-building tasks calibrated to each student's level (Erikson — Industry). A critic says 'these are separate programs addressing separate theories.' The BEST response is:",c:["A. The critic is right — each theory addresses a different domain and should be implemented separately","B. The reforms are actually deeply integrated — meeting physiological needs (Maslow) enables students to engage in ZPD-based peer learning (Vygotsky), which builds competence and resolves the Industry crisis (Erikson) simultaneously","C. Only one of the three reforms addresses learning theory; the others address social work","D. These three reforms address the Macrosystem (Bronfenbrenner) and therefore operate independently of classroom-level theories"],a:"B",e:"The three reforms are deeply integrated: Maslow's needs satisfaction ENABLES Vygotskian engagement, which BUILDS the competence that resolves Erikson's Industry vs. Inferiority — they work together, not separately."},
  {id:"cald-298",d:"difficult",t:"Kohlberg and Moral Education",q:"A teacher uses dilemma discussions (presenting ethical dilemmas for class debate) as a moral education strategy. Kohlberg argued this works because:",c:["A. Exposure to dilemmas directly conditions moral behavior through reinforcement","B. Discussing dilemmas at a stage SLIGHTLY ABOVE the student's current stage creates cognitive disequilibrium that motivates upward moral stage movement","C. Dilemma discussions activate unconscious moral conflicts (Freud) that lead to moral growth","D. Students learn moral behavior by observing the teacher model the correct solution (Bandura)"],a:"B",e:"Kohlberg's dilemma discussion method works by exposing students to moral reasoning slightly above their current stage — this creates cognitive disequilibrium (paralleling Piaget's mechanism) that motivates moral stage advancement."},
  {id:"cald-299",d:"difficult",t:"Bronfenbrenner Advanced",q:"Bronfenbrenner's later work added the concept of PROXIMAL PROCESSES — the 'engines of development' — which refer to enduring forms of increasingly complex, reciprocal interaction between an active human organism and its environment. Which classroom practice BEST embodies Proximal Processes?",c:["A. Providing students with standardized tests at the end of each quarter","B. Establishing consistent, long-term, challenging, reciprocal interactions between teacher and student — relationships that grow in complexity over time","C. Displaying culturally diverse materials on classroom walls (Macrosystem influence)","D. Adjusting school policy to mandate smaller class sizes (Exosystem influence)"],a:"B",e:"Proximal Processes are enduring, reciprocal, increasingly complex interactions — consistent, long-term teacher-student relationships that grow in complexity over time are the classroom embodiment of this concept."},
  {id:"cald-300",d:"difficult",t:"Integrated Theories",q:"A theorist proposes: 'Cognitive development (Piaget), social learning (Vygotsky/Bandura), moral development (Kohlberg), psychosocial development (Erikson), need fulfillment (Maslow), and ecological context (Bronfenbrenner) are NOT separate systems but are SIMULTANEOUS, INTERACTING dimensions of a SINGLE developing person.' The STRONGEST argument SUPPORTING this integrated view is:",c:["A. Each theory addresses exactly the same phenomenon from the same angle","B. Research shows that cognitive, moral, social, emotional, and ecological factors always develop at exactly the same rate","C. A child's cognitive stage (Piaget) affects their moral reasoning capacity (Kohlberg); unmet needs (Maslow) impair psychosocial crisis resolution (Erikson); ecological context (Bronfenbrenner) shapes ALL domains simultaneously — the person is a unified system, not a collection of separate modules","D. All developmental theories converge on the same practical classroom strategies regardless of their theoretical differences"],a:"C",e:"The strongest argument: cognitive stage limits moral reasoning capacity; needs affect psychosocial resolution; ecology shapes all domains — these are not separate modules but interacting dimensions of ONE unified developing person."},
];
